151	export const runScenario = (input: unknown): unknown => {
152	  const scenario = input as Scenario;
153	  const policies: PolicyState[] = [];
154	  let quoteCount = 0;
155	  const results = scenario.steps.map((step) => {
156	    if (step.op === "quote") {
157	      const ctx: CustomerContext = {
158	        yearsWithMHPCO: scenario.customer.yearsWithMHPCO,
159	        isFollowUpContract: quoteCount > 0,
160	      };
161	      quoteCount += 1;
162	      policies.push(createPolicy(step.items));
163	      return computeQuote(step, ctx);
164	    }
165	    const policy = policies[step.policy];
166	    return claimStep(step, policy);
167	  });
168	  return { results };
169	};
